INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Math1', 'Sequences & Series', 1, 'ลำดับเลขคณิตชุดหนึ่งคือ 5, 9, 13, 17, ... จงหาพจน์ที่ 10 (a10) ของลำดับนี้', '37', '41', '45', '49', '53', 'b', 'ใช้สูตร an = a1 + (n-1)d เลย Nas! ข้อนี้ a1=5, d=4 จะได้ 5 + (9 * 4) = 5 + 36 = 41'),
('Math1', 'Sequences & Series', 2, 'ลำดับเรขาคณิตชุดหนึ่งมีพจน์แรก (a1) เท่ากับ 3 และมีอัตราส่วนร่วม (r) เท่ากับ 2 จงหาพจน์ที่ 5 (a5)', '24', '48', '96', '12', '15', 'b', 'สูตรเรขาคณิตคือ an = a1 * r^(n-1) จะได้ 3 * 2^4 = 3 * 16 = 48'),
('Math1', 'Sequences & Series', 2, 'จงหาผลบวก 10 พจน์แรก (S10) ของอนุกรมเลขคณิต 1 + 2 + 3 + ... + 10', '45', '50', '55', '60', '65', 'c', 'สูตร Sn = n/2(a1 + an) จะได้ 10/2 * (1 + 10) = 5 * 11 = 55'),
('Math1', 'Sequences & Series', 3, 'พจน์ที่เท่าใดของลำดับเลขคณิต 7, 13, 19, ... มีค่าเท่ากับ 127?', 'พจน์ที่ 19', 'พจน์ที่ 20', 'พจน์ที่ 21', 'พจน์ที่ 22', 'พจน์ที่ 23', 'c', 'แก้สมการ 127 = 7 + (n-1)6 จะได้ 120 = (n-1)6 นำ 6 ไปหารได้ 20 = n-1 ดังนั้น n = 21'),
('Math1', 'Sequences & Series', 3, 'อนุกรมเรขาคณิตไม่สิ้นสุด (Infinite Series) 1 + 1/2 + 1/4 + 1/8 + ... มีผลบวกเท่ากับเท่าใด?', '1', '1.5', '2', 'Infinity', 'หาค่าไม่ได้', 'c', 'สูตรอนุกรมอนันต์คือ S = a1 / (1 - r) จะได้ 1 / (1 - 0.5) = 2'),
('Math1', 'Statistics', 1, 'ข้อมูลคะแนนสอบของเพื่อน 5 คนคือ 12, 15, 15, 18, 20 จงหาค่า "ฐานนิยม" (Mode) ของข้อมูลชุดนี้', '15', '16', '18', '20', 'ไม่มีฐานนิยม', 'a', 'ฐานนิยมคือตัวที่ซ้ำกันมากที่สุด ในชุดนี้คือ 15'),
('Math1', 'Statistics', 2, 'z-score ของคะแนน 85 เมื่อค่าเฉลี่ย=75 และ SD=5 คือเท่าใด?', '1', '1.5', '2', '2.5', '3', 'c', 'z = (85 - 75) / 5 = 2'),
('Math1', 'Statistics', 3, 'ข้อมูลที่มี Outliers ควรใช้ค่ากลางชนิดใด?', 'ค่าเฉลี่ย', 'มัธยฐาน', 'ฐานนิยม', 'พิสัย', 'หาไม่ได้', 'b', 'มัธยฐานเสถียรกว่าเพราะไม่โดนค่าสุดโต่งดึงความหมายไป'),
('Math1', 'Calculus', 3, 'อนุพันธ์ของ f(x) = x³ + 5x² - 4 ที่จุด x = 1 คือเท่าใด?', '3', '10', '13', '15', '18', 'c', 'f''(x) = 3x² + 10x แทนค่า x=1 ได้ 13');
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('Physics', 'Newton Laws', 2, 'ออกแรงผลักกล่อง 10 kg ด้วยแรง 50 N บนพื้นลื่น กล่องจะมีความเร่งเท่าใด?', '2 m/s²', '5 m/s²', '10 m/s²', '20 m/s²', '50 m/s²', 'b', 'ΣF = ma -> 50 = 10a -> a = 5'),
('Physics', 'Direct Current', 3, 'ตัวต้านทาน 3 โอห์ม และ 6 โอห์ม ต่อแบบ "ขนาน" กัน จะมีความต้านทานรวมเท่าใด?', '2 โอห์ม', '4.5 โอห์ม', '9 โอห์ม', '18 โอห์ม', '0.5 โอห์ม', 'a', '(3 * 6) / (3 + 6) = 18 / 9 = 2 โอห์ม'),
('Physics', 'Fluids', 3, 'ตามหลักแบร์นูลลี บริเวณที่ของไหลเคลื่อนที่เร็ว ความดันจะเป็นอย่างไร?', 'สูงขึ้น', 'ต่ำลง', 'คงที่', 'เป็นศูนย์', 'เปลี่ยนตามอุณหภูมิ', 'b', 'วิ่งเร็ว ความดันต่ำ นี่คือหลักการยกปีกเครื่องบิน'),
('Physics', 'Heat', 3, '27 °C คิดเป็นกี่เคลวิน (Kelvin)?', '27 K', '127 K', '273 K', '300 K', '373 K', 'd', 'K = °C + 273 ดังนั้น 27 + 273 = 300 K');
INSERT INTO questions (subject, chapter, level, question_text, option_a, option_b, option_c, option_d, option_e, correct_option, explanation)
VALUES 
('TPAT3', 'Drawing', 2, 'เส้นที่ใช้แสดงขอบของวัตถุที่ถูกบังอยู่ (Hidden Line) คือเส้นอะไร?', 'เส้นเต็มหนา', 'เส้นเต็มบาง', 'เส้นประ', 'เส้นศูนย์กลาง', 'เส้นมือเปล่า', 'c', 'ส่วนที่มองไม่เห็นแต่มีอยู่จริงใช้เส้นประ'),
('Engineering', 'Materials', 2, 'วัสดุใดที่มีความแข็ง (Hardness) สูงแต่เปราะแตกง่าย?', 'เหล็กเหนียว', 'อลูมิเนียม', 'เซรามิก', 'ทองแดง', 'พลาสติก', 'c', 'เซรามิกแข็งแต่เปราะ เหมือนจานตกแล้วแตก'),
('Engineering', 'Manufacturing', 2, 'การผลิตโดยทำให้โลหะร้อนจนละลายแล้วเทลงแม่พิมพ์คืออะไร?', 'การกลึง', 'การเชื่อม', 'การหล่อ (Casting)', 'การกัด', 'การปั๊ม', 'c', 'การหล่อคือการเปลี่ยนสถานะโลหะเป็นของเหลวเพื่อขึ้นรูป');